// math-client.module.ts
import { Module } from '@nestjs/common';
import { ClientsModule, Transport } from '@nestjs/microservices';
import { MathClientService } from './math-client.service';

@Module({
  imports: [
    ClientsModule.register([
      {
        name: 'MATH_SERVICE',
        transport: Transport.TCP,
        options: { host: 'localhost', port: 3001 },
      },
    ]),
  ],
  providers: [MathClientService],
  exports: [MathClientService],
})
export class MathClientModule {}

// math-client.service.ts
import { Injectable, Inject, OnModuleInit } from '@nestjs/common';
import { ClientProxy } from '@nestjs/microservices';
import { lastValueFrom } from 'rxjs';

@Injectable()
export class MathClientService implements OnModuleInit {
  constructor(@Inject('MATH_SERVICE') private client: ClientProxy) {}

  async add(a: number, b: number): Promise<number> {
    return lastValueFrom(this.client.send('add', { a, b }));
  }

  async onModuleInit() {
    await this.client.connect();
  }
}
