import { RpcException } from '@nestjs/microservices';

@MessagePattern('add')
add(@Payload() data: { a: number; b: number }): number {
  if (data.a < 0 || data.b < 0) {
    throw new RpcException({
      code: 'INVALID_NUMBER',
      message: 'Les nombres ne peuvent pas être négatifs',
    });
  }
  return data.a + data.b;
}

// Côté client, l'erreur est capturée :
try {
  await client.send('add', { a: -1, b: 2 }).toPromise();
} catch (error) {
  console.log(error.code); // 'INVALID_NUMBER'
}
