// math.controller.spec.ts
import { Test, TestingModule } from '@nestjs/testing';
import { INestApplication } from '@nestjs/common';
import { MicroserviceOptions, Transport, ClientProxy, ClientProxyFactory } from '@nestjs/microservices';
import { MathController } from './math.controller';

describe('MathController (microservice)', () => {
  let app: INestApplication;
  let client: ClientProxy;

  beforeAll(async () => {
    const module: TestingModule = await Test.createTestingModule({
      controllers: [MathController],
    }).compile();

    app = module.createNestApplication();
    app.connectMicroservice<MicroserviceOptions>({
      transport: Transport.TCP,
      options: { port: 3002 }, // port de test
    });
    await app.startAllMicroservices();

    client = ClientProxyFactory.create({
      transport: Transport.TCP,
      options: { port: 3002 },
    });
    await client.connect();
  });

  afterAll(async () => {
    await client.close();
    await app.close();
  });

  it('devrait additionner 2 et 3', async () => {
    const result = await client.send('add', { a: 2, b: 3 }).toPromise();
    expect(result).toBe(5);
  });

  it('devrait lancer une exception pour nombre négatif', async () => {
    try {
      await client.send('add', { a: -1, b: 5 }).toPromise();
      fail('Exception non levée');
    } catch (error) {
      expect(error.code).toBe('INVALID_NUMBER');
    }
  });
});
